import List from '@universe-design/rc-virtual-list';
import * as React from 'react';
import { useTreeContext } from './hooks/TreeContext';
import type { DoublyTreeNode } from './util';
import { InternalTreeNode } from './InternalTreeNode';
import { HighlightProvider } from '../shared';
import { ListItemLike } from '../shared/components/list';

export const TreeContainer: React.FC = () => {
  const { finalTreeNodeList, rootCssScope, height, virtual, listRef, searchValue, notFoundContent } = useTreeContext();

  const listNode = (
    <div className={rootCssScope('__list')}>
      <List<DoublyTreeNode>
        itemKey={node => node.__node__.value}
        ref={listRef}
        data={finalTreeNodeList}
        height={height}
        itemHeight={32}
        fullHeight={false}
        // onScroll={onPopupScroll}
        virtual={virtual}
        // onMouseEnter={onMouseEnter}
      >
        {node => (
          // 这里加一个空 div 是为了把内部带 margin 的元素包住，让 virtual list 能正常计算，tree，select，cascader
          <div>
            <InternalTreeNode key={node.__node__.value} doublyTreeNode={node} />
          </div>
        )}
      </List>
    </div>
  );

  const notFoundNode = (() => {
    if (notFoundContent === null) {
      return null;
    }
    return <ListItemLike className={rootCssScope('__empty')}>{notFoundContent}</ListItemLike>;
  })();

  return (
    <HighlightProvider
      value={React.useMemo(
        () => ({
          searchWords: searchValue ? [searchValue] : undefined,
          disabled: false,
        }),
        [searchValue],
      )}
    >
      <div className={rootCssScope()}>{finalTreeNodeList.length ? listNode : notFoundNode}</div>
    </HighlightProvider>
  );
};
